  1→import { readdir } from "node:fs/promises";
  2→import { homedir } from "node:os";
  3→import { getGitRemoteUrl, normalizeRemoteUrl } from "./git-info.js";
  4→import {
  5→	cacheRemote,
  6→	cacheRemotes,
  7→	getCachedRemote,
  8→	getRemoteCache,
  9→} from "./remote-cache.js";
 10→import { decodeProjectPath, SESSIONS_BASE_DIR } from "./session-resolver.js";
 11→
 12→export interface ScannedProject {
 13→	encodedDir: string;
 14→	decodedPath: string;
 15→	displayPath: string;
 16→	sessionDir: string;
 17→	sessionCount: number;
 18→	sessionIds: string[];
 19→}
