 28→	let projectDirs: string[];
 29→	try {
 30→		projectDirs = await readdir(SESSIONS_BASE_DIR);
 31→	} catch {
 32→		return [];
 33→	}
 34→
 35→	const home = homedir();
 36→	const projects: ScannedProject[] = [];
 37→
 38→	for (const dir of projectDirs) {
 39→		const sessionDir = `${SESSIONS_BASE_DIR}/${dir}`;
 40→		let files: string[];
 41→		try {
 42→			files = await readdir(sessionDir);
 43→		} catch {
 44→			continue;
 45→		}
 46→
 47→		const sessionIds = files
 48→			.filter((f) => f.endsWith(".jsonl") && !f.startsWith("agent-"))
 49→			.map((f) => f.replace(/\.jsonl$/, ""));
 50→
 51→		if (sessionIds.length === 0) continue;
 52→
 53→		const decodedPath = await decodeProjectPath(dir);
 54→		const displayPath = decodedPath.startsWith(home)
 55→			? `~${decodedPath.slice(home.length)}`
 56→			: decodedPath;
 57→
 58→		projects.push({
 59→			encodedDir: dir,
 60→			decodedPath,
 61→			displayPath,
 62→			sessionDir,
 63→			sessionCount: sessionIds.length,
 64→			sessionIds,
 65→		});
 66→	}
 67→
 68→	return projects;
 69→}
 70→
 71→export function groupProjectsForCwd(
 72→	projects: ScannedProject[],
 73→	cwd: string,
 74→): GroupedProjects {
 75→	const current = projects.find((p) => p.decodedPath === cwd);
 76→	const subfolders = projects.filter(
 77→		(p) =>
 78→			p !== current &&
 79→			current !== undefined &&
 80→			p.decodedPath.startsWith(`${current.decodedPath}/`),
 81→	);
 82→	const others = projects.filter(
 83→		(p) => p !== current && !subfolders.includes(p),
 84→	);
 85→
 86→	subfolders.sort((a, b) => a.decodedPath.localeCompare(b.decodedPath));
 87→	others.sort((a, b) => a.displayPath.localeCompare(b.displayPath));
 88→
 89→	return { current, subfolders, others };
 90→}
 91→
 92→export interface ProjectGroup {
 93→	displayName: string;
 94→	gitRemote: string | null;
 95→	projects: ScannedProject[];
 96→	totalSessions: number;
 97→	containsCwd: boolean;
 98→}
 99→
100→function extractDisplayName(normalized: string): string {
101→	// "github.com/owner/repo" → "owner/repo"
102→	const parts = normalized.split("/");
103→	if (parts.length >= 3) {
104→		return parts.slice(1).join("/");
105→	}
106→	return normalized;
107→}
108→
109→export async function groupProjectsByRemote(
110→	projects: ScannedProject[],
111→	cwd: string,
112→): Promise<ProjectGroup[]> {
113→	const cache = await getRemoteCache();
114→	let cacheUpdated = false;
115→
116→	const remotes = await Promise.all(
117→		projects.map((p) => getGitRemoteUrl(p.decodedPath)),
118→	);
119→
120→	const grouped = new Map<
121→		string,
122→		{ remote: string; projects: ScannedProject[] }
123→	>();
124→	const ungrouped: ScannedProject[] = [];
125→
126→	for (let i = 0; i < projects.length; i++) {
127→		const project = projects[i] as ScannedProject;
128→		const remote = remotes[i];
129→
130→		if (remote) {
131→			const normalized = normalizeRemoteUrl(remote);
132→			// Cache newly resolved remotes
133→			if (getCachedRemote(cache, project.encodedDir) !== normalized) {
134→				cacheRemote(cache, project.encodedDir, normalized);
135→				cacheUpdated = true;
136→			}
137→			const existing = grouped.get(normalized);
138→			if (existing) {
139→				existing.projects.push(project);
140→			} else {
141→				grouped.set(normalized, { remote: normalized, projects: [project] });
142→			}
143→		} else {
144→			// Try cache for ungrouped projects
145→			const cached = getCachedRemote(cache, project.encodedDir);
146→			if (cached) {
147→				const existing = grouped.get(cached);
148→				if (existing) {
149→					existing.projects.push(project);
150→				} else {
151→					grouped.set(cached, { remote: cached, projects: [project] });
152→				}
153→			} else {
154→				ungrouped.push(project);
155→			}
156→		}
157→	}
158→
159→	const groups: ProjectGroup[] = [];
160→
161→	for (const [, entry] of grouped) {
162→		const containsCwd = entry.projects.some(
163→			(p) => cwd === p.decodedPath || cwd.startsWith(`${p.decodedPath}/`),
164→		);
165→		groups.push({
166→			displayName: extractDisplayName(entry.remote),
167→			gitRemote: entry.remote,
168→			projects: entry.projects,
169→			totalSessions: entry.projects.reduce((s, p) => s + p.sessionCount, 0),
170→			containsCwd,
171→		});
172→	}
173→
174→	// Second pass: match ungrouped projects to existing groups by path similarity.
175→	// Deleted Conductor workspaces have no git remote, but share a path prefix
176→	// (e.g. ~/conductor/workspaces/rudel/) with existing workspaces that do.
177→	const homeSegments = homedir().split("/").length;
178→	const remainingUngrouped: ScannedProject[] = [];
179→
180→	for (const project of ungrouped) {
181→		const match = findBestGroupByPath(project, groups, homeSegments);
182→		if (match) {
183→			match.projects.push(project);
184→			match.totalSessions += project.sessionCount;
185→			if (
186→				cwd === project.decodedPath ||
187→				cwd.startsWith(`${project.decodedPath}/`)
188→			) {
189→				match.containsCwd = true;
190→			}
191→		} else {
192→			remainingUngrouped.push(project);
193→		}
194→	}
195→
196→	for (const project of remainingUngrouped) {
197→		const containsCwd =
198→			cwd === project.decodedPath || cwd.startsWith(`${project.decodedPath}/`);
199→		groups.push({
200→			displayName: project.displayPath,
201→			gitRemote: null,
202→			projects: [project],
203→			totalSessions: project.sessionCount,
204→			containsCwd,
205→		});
206→	}
207→
208→	groups.sort((a, b) => {
209→		if (a.containsCwd !== b.containsCwd) return a.containsCwd ? -1 : 1;
210→		const aHasRemote = a.gitRemote !== null;
211→		const bHasRemote = b.gitRemote !== null;
212→		if (aHasRemote !== bHasRemote) return aHasRemote ? -1 : 1;
213→		return a.displayName.localeCompare(b.displayName);
214→	});
215→
216→	// Fire-and-forget cache write
217→	if (cacheUpdated) {
218→		cacheRemotes(cache);
219→	}
220→
221→	return groups;
222→}
223→
224→function commonPrefixLength(a: string, b: string): number {
225→	const partsA = a.split("/");
226→	const partsB = b.split("/");
227→	let count = 0;
228→	for (let i = 0; i < Math.min(partsA.length, partsB.length); i++) {
229→		if (partsA[i] === partsB[i]) count++;
230→		else break;
231→	}
232→	return count;
233→}
234→
235→function findBestGroupByPath(
236→	project: ScannedProject,
237→	groups: ProjectGroup[],
238→	homeSegments: number,
239→): ProjectGroup | null {
240→	let bestGroup: ProjectGroup | null = null;
241→	let bestLen = 0;
242→	let secondBestLen = 0;
243→
244→	for (const group of groups) {
245→		if (!group.gitRemote) continue;
246→
247→		let groupBest = 0;
248→		for (const p of group.projects) {
249→			groupBest = Math.max(
250→				groupBest,
251→				commonPrefixLength(project.decodedPath, p.decodedPath),
252→			);
253→		}
254→
255→		if (groupBest > bestLen) {
256→			secondBestLen = bestLen;
257→			bestLen = groupBest;
258→			bestGroup = group;
259→		} else if (groupBest > secondBestLen) {
260→			secondBestLen = groupBest;
261→		}
262→	}
263→
264→	// Must extend beyond home dir AND be strictly better than second-best
265→	if (bestGroup && bestLen > homeSegments && bestLen > secondBestLen) {
266→		return bestGroup;
267→	}
268→	return null;
269→}
