 33→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 34→	const credentials = loadCredentials();
 35→	if (!credentials && !flags.dryRun) {
 36→		p.log.error("Not authenticated. Run `rudel login` first.");
 37→		process.exitCode = 1;
 38→		return;
 39→	}
 40→
 41→	p.intro("rudel upload");
 42→
 43→	const spin = p.spinner();
 44→	spin.start("Scanning projects...");
 45→	const projects = await scanProjects();
 46→	spin.stop(`Found ${projects.length} project(s)`);
 47→
 48→	if (projects.length === 0) {
 49→		p.log.warn("No projects with sessions found in ~/.claude/projects/");
 50→		p.outro("Nothing to upload.");
 51→		return;
 52→	}
 53→
 54→	const cwd = process.cwd();
 55→	spin.start("Grouping by git remote...");
 56→	const groups = await groupProjectsByRemote(projects, cwd);
 57→	spin.stop(`Found ${groups.length} group(s)`);
 58→
 59→	const options: Array<{
 60→		value: ProjectGroup;
 61→		label: string;
 62→		hint: string;
 63→	}> = [];
 64→	const preSelected: ProjectGroup[] = [];
 65→
 66→	for (const group of groups) {
 67→		const label =
 68→			group.projects.length > 1
 69→				? group.displayName
 70→				: (group.projects[0]?.displayPath ?? group.displayName);
 71→		const hint =
 72→			group.projects.length > 1
 73→				? `${sessionCountHint(group.totalSessions)}, ${group.projects.length} locations`
 74→				: sessionCountHint(group.totalSessions);
 75→		options.push({ value: group, label, hint });
 76→		if (group.containsCwd) {
 77→			preSelected.push(group);
 78→		}
 79→	}
 80→
 81→	const selected = await p.multiselect({
 82→		message: "Select projects to upload",
 83→		options,
 84→		initialValues: preSelected,
 85→		required: true,
 86→	});
 87→
 88→	if (p.isCancel(selected)) {
 89→		p.cancel("Upload cancelled.");
 90→		return;
 91→	}
 92→
 93→	const selectedProjects = selected.flatMap((g) => g.projects);
 94→	const totalSessions = selected.reduce((sum, g) => sum + g.totalSessions, 0);
 95→	p.log.info(
 96→		`Uploading ${totalSessions} session(s) from ${selectedProjects.length} project(s)`,
 97→	);
 98→
 99→	const batchOpts: BatchOptions = {
100→		tag: flags.tag,
101→		classify: flags.classify,
102→		dryRun: flags.dryRun,
103→		org: flags.org,
104→		uploadConfig: {
105→			endpoint: flags.endpoint,
106→			token: credentials?.token ?? "",
107→		},
108→	};
109→
110→	const uploadSpin = p.spinner();
111→	uploadSpin.start("Uploading sessions...");
112→
113→	const result = await batchUpload(
114→		selectedProjects,
115→		batchOpts,
116→		(current, total) => {
117→			uploadSpin.message(`[${current}/${total}] Uploading...`);
118→		},
119→	);
120→
121→	uploadSpin.stop("Upload complete");
122→
123→	if (result.succeeded > 0) {
