125→	}
126→	if (result.failed > 0) {
127→		p.log.error(`${result.failed} session(s) failed`);
128→		for (const err of result.errors.slice(0, 5)) {
129→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
130→		}
131→		if (result.errors.length > 5) {
132→			p.log.warn(`  ...and ${result.errors.length - 5} more`);
133→		}
134→	}
135→
136→	if (flags.dryRun) {
137→		p.outro("Dry run complete — no sessions were uploaded.");
138→	} else {
139→		p.outro("Done!");
140→	}
141→
142→	if (result.failed > 0) {
143→		process.exitCode = 1;
144→	}
145→}
