290→				kind: "enum",
291→				values: [...SESSION_TAGS],
292→				brief: "Session tag/category",
293→				optional: true,
294→			},
295→			endpoint: {
296→				kind: "parsed",
297→				parse: String,
298→				brief: "Override the upload endpoint URL",
299→				default: DEFAULT_ENDPOINT,
300→			},
301→			classify: {
302→				kind: "boolean",
303→				brief: "Auto-classify session tag using Claude CLI",
304→				default: false,
305→			},
306→			dryRun: {
307→				kind: "boolean",
308→				brief: "Preview what would be uploaded without sending",
309→				default: false,
310→			},
311→			org: {
312→				kind: "parsed",
313→				parse: String,
314→				brief: "Override the organization ID to upload to",
315→				optional: true,
316→			},
317→		},
318→		aliases: {
319→			t: "tag",
320→			c: "classify",
321→			n: "dryRun",
322→			o: "org",
323→		},
324→	},
325→	docs: {
326→		brief:
327→			"Upload Claude Code session transcripts. No args = interactive project picker.",
328→	},
329→});
