export function toSessionFiles(projects: ScannedProject[]): SessionFile[] {
	return projects.flatMap((project) =>
		project.sessionIds.map((sessionId) => ({
			sessionId,
			transcriptPath: `${project.sessionDir}/${sessionId}.jsonl`,
			projectPath: project.decodedPath,
		})),
	);
}

/**
 * Find all sessions belonging to the same repository as `cwd`.
 * Uses the same scan + group-by-remote logic as the upload command.
 */
export async function findSessionsForCwd(cwd: string): Promise<SessionFile[]> {
	const projects = await scanProjects();
	if (projects.length === 0) return [];

	const groups = await groupProjectsByRemote(projects, cwd);
	const cwdGroup = groups.find((g) => g.containsCwd);
	if (!cwdGroup) return [];

	return toSessionFiles(cwdGroup.projects);
}

function commonPrefixLength(a: string, b: string): number {
	const partsA = a.split("/");
	const partsB = b.split("/");
	let count = 0;
	for (let i = 0; i < Math.min(partsA.length, partsB.length); i++) {
		if (partsA[i] === partsB[i]) count++;
		else break;
	}
	return count;
}

function findBestGroupByPath(
	project: ScannedProject,
	groups: ProjectGroup[],
	homeSegments: number,
): ProjectGroup | null {
	let bestGroup: ProjectGroup | null = null;
	let bestLen = 0;
	let secondBestLen = 0;

	for (const group of groups) {
		if (!group.gitRemote) continue;

		let groupBest = 0;
		for (const p of group.projects) {
			groupBest = Math.max(
				groupBest,
				commonPrefixLength(project.decodedPath, p.decodedPath),
			);
		}

		if (groupBest > bestLen) {
			secondBestLen = bestLen;
			bestLen = groupBest;
			bestGroup = group;
		} else if (groupBest > secondBestLen) {
			secondBestLen = groupBest;
		}
	}

	// Must extend beyond home dir AND be strictly better than second-best
	if (bestGroup && bestLen > homeSegments && bestLen > secondBestLen) {
		return bestGroup;
	}
	return null;
}

