 93→		p.log.success(`Auto-upload hook enabled in ${agent.getHookSettingsPath()}`);
 94→	}
 95→
 96→	// Check for existing sessions to upload
 97→	const sessions = await agent.findProjectSessions(cwd);
 98→	if (sessions.length === 0) {
 99→		p.outro("Done!");
100→		return;
101→	}
102→
103→	const shouldUpload = await p.confirm({
104→		message: `Found ${sessions.length} previous session(s). Upload them now?`,
105→		initialValue: false,
106→	});
107→
108→	if (p.isCancel(shouldUpload) || !shouldUpload) {
109→		p.outro("Done!");
110→		return;
111→	}
112→
113→	const endpoint = `${credentials.apiBaseUrl}/rpc`;
114→	let failed = 0;
115→
116→	await p.tasks(
117→		sessions.map((session, i) => ({
118→			title: `[${i + 1}/${sessions.length}] ${session.sessionId}`,
119→			task: async (message) => {
120→				message("Reading transcript...");
121→				try {
122→					const content = await readTranscript(session.transcriptPath);
123→					const agentIds = extractAgentIds(content);
124→					const sessionDir = dirname(session.transcriptPath);
125→					const subagents =
126→						agentIds.length > 0
127→							? await readSubagentFiles(sessionDir, agentIds, session.sessionId)
128→							: [];
129→
130→					message("Resolving git info...");
131→					const gitInfo = await getGitInfo(session.projectPath);
132→
133→					const request: IngestRequest = {
134→						sessionId: session.sessionId,
135→						projectPath: session.projectPath,
136→						repository: gitInfo.repository,
137→						gitBranch: gitInfo.branch,
138→						gitSha: gitInfo.sha,
139→						content,
140→						subagents: subagents.length > 0 ? subagents : undefined,
141→						organizationId: selectedOrgId,
142→					};
143→
144→					message("Uploading...");
145→					const result = await uploadSession(request, {
146→						endpoint,
147→						token: credentials.token,
148→					});
149→
150→					if (result.success) {
151→						return "Uploaded";
152→					}
153→					failed++;
154→					return `Failed: ${result.error}`;
155→				} catch (error) {
156→					failed++;
157→					return `Error: ${error instanceof Error ? error.message : String(error)}`;
158→				}
159→			},
160→		})),
161→	);
162→
163→	if (failed > 0) {
164→		p.log.error(`${failed} session(s) failed`);
165→	}
166→
167→	p.outro("Done!");
168→}
